39	fn macro_with_flags(
40	    name: &str,
41	    phrase: &str,
42	    if_flag: Option<&str>,
43	    set_flag: Option<&str>,
44	    keys: Vec<KeyAction>,
45	) -> MacroConfig {
46	    MacroConfig {
47	        name: name.to_string(),
48	        phrase: Some(phrase.to_string()),
49	        if_flag: if_flag.map(str::to_string),
50	        set_flag: set_flag.map(str::to_string),
51	        sound: None,
52	        keys,
53	    }
