56	/// Build a realistic Helldivers 2 stratagem pack with multiple categories.
57	/// Stratagem key sequences: W=up, S=down, A=left, D=right.
58	fn hd2_pack() -> Pack {
59	    let stratagems = Category {
60	        name: "Stratagems".to_string(),
61	        macros: vec![
62	            macro_simple(
63	                "Reinforce",
64	                "reinforce",
65	                vec![
66	                    key("KEY_W"), key("KEY_S"), key("KEY_D"),
67	                    key("KEY_W"), key("KEY_A"),
68	                ],
69	            ),
70	            macro_simple(
71	                "Resupply",
72	                "resupply",
73	                vec![
74	                    key("KEY_S"), key("KEY_S"), key("KEY_W"), key("KEY_D"),
75	                ],
76	            ),
77	            macro_simple(
78	                "Eagle Airstrike",
79	                "eagle airstrike",
80	                vec![
81	                    key("KEY_W"), key("KEY_D"), key("KEY_S"), key("KEY_D"),
82	                ],
83	            ),
84	            macro_simple(
85	                "Orbital Laser",
86	                "orbital laser",
87	                vec![
88	                    key("KEY_D"), key("KEY_W"), key("KEY_D"), key("KEY_S"),
89	                    key("KEY_D"),
90	                ],
91	            ),
92	            macro_simple(
93	                "SOS Beacon",
94	                "sos beacon",
95	                vec![
96	                    key("KEY_W"), key("KEY_S"), key("KEY_D"), key("KEY_W"),
97	                ],
98	            ),
99	        ],
100	    };
101	
102	    let support_weapons = Category {
103	        name: "Support Weapons".to_string(),
104	        macros: vec![
105	            macro_simple(
106	                "Anti-Tank Mines",
107	                "anti tank mines",
108	                vec![
109	                    key("KEY_S"), key("KEY_W"), key("KEY_D"), key("KEY_A"),
110	                ],
111	            ),
112	            macro_simple(
113	                "Machine Gun Sentry",
114	                "machine gun sentry",
115	                vec![
116	                    key("KEY_S"), key("KEY_W"), key("KEY_D"), key("KEY_W"),
117	                    key("KEY_A"),
118	                ],
119	            ),
120	        ],
121	    };
122	
123	    let flags = Category {
124	        name: "Flag-gated Stratagems".to_string(),
125	        macros: vec![
126	            macro_with_flags(
127	                "Hellbomb Arm",
128	                "arm hellbomb",
129	                Some("hellbomb_present"),
130	                Some("hellbomb_armed"),
131	                vec![key_timed("KEY_E", 200, 100)],
132	            ),
133	            macro_with_flags(
134	                "Clear Hellbomb Flag",
135	                "hellbomb gone",
136	                None,
137	                Some("hellbomb_armed"),
138	                vec![],
139	            ),
140	        ],
141	    };
142	
143	    Pack {
144	        name: "Helldivers 2".to_string(),
145	        author: Some("community".to_string()),
146	        categories: vec![stratagems, support_weapons, flags],
147	    }
148	}
