193	    let hellbomb = flat.iter().find(|m| m.name == "Hellbomb Arm").unwrap();
194	    assert_eq!(hellbomb.if_flag, Some("hellbomb_present".to_string()));
195	    assert_eq!(hellbomb.set_flag, Some("hellbomb_armed".to_string()));
196	    assert_eq!(hellbomb.keys[0].dwell_ms, Some(200));
197	    assert_eq!(hellbomb.keys[0].gap_ms, Some(100));
198	}
