326	#[test]
327	fn pack_import_from_zip_reads_name_and_macros() {
328	    // Build a zip in a temp dir, import it, and verify the imported pack content.
329	    // import() extracts to XDG_CONFIG_HOME/hd-linux-voice/profiles/<name>.
330	    // We redirect XDG_CONFIG_HOME to a second temp dir to stay hermetic.
331	    let source_dir = tempfile::tempdir().unwrap();
332	    let import_root = tempfile::tempdir().unwrap();
333	
334	    let pack = Pack {
335	        name: "ImportTest".to_string(),
336	        author: Some("tester".to_string()),
337	        categories: vec![Category {
338	            name: "Test".to_string(),
339	            macros: vec![macro_simple(
340	                "Reinforce",
341	                "reinforce",
342	                vec![key("KEY_W"), key("KEY_S")],
343	            )],
344	        }],
345	    };
346	    pack.save_to_dir(source_dir.path()).unwrap();
347	
348	    let zip_path = source_dir.path().join("importtest.hdpack");
349	    pack.export(source_dir.path(), &zip_path).unwrap();
350	
351	    // Redirect XDG so import() writes into our temp dir, not the real config home.
352	    std::env::set_var("XDG_CONFIG_HOME", import_root.path());
353	    let imported = Pack::import(&zip_path).expect("import must succeed");
354	    std::env::remove_var("XDG_CONFIG_HOME");
355	
356	    assert_eq!(imported.name, "ImportTest");
357	    assert_eq!(imported.author, Some("tester".to_string()));
358	    assert_eq!(imported.categories.len(), 1);
359	
360	    let flat = imported.flatten();
361	    assert_eq!(flat.len(), 1);
362	    assert_eq!(flat[0].name, "Reinforce");
363	}
